parameters.jsonBody:
={
  "trigger_id": "{{ $json.trigger_id }}",
  "url": "{{ $json.webhook_url }}", 
  "dialog": {
    "callback_id": "submit_new_alert",
    "title": "Create New Lunch Alert",
    "icon_url": "https://cdn-icons-png.flaticon.com/512/1828/1828819.png",
    "elements": [
      {
        "display_name": "Keyword to Track",
        "name": "keyword",
        "type": "text",
        "subtype": "text",
        "placeholder": "e.g., Pizza, Schnitzel, Falafel",
        "help_text": "Case-insensitive. You'll get notified when this word appears on the menu.",
        "optional": false
      },
      {
        "display_name": "Menu Preference",
        "name": "diet",
        "type": "select",
        "options": [
          {"text": "🥩 All Menus", "value": "all"},
          {"text": "🥬 Vegetarian", "value": "veggie"},
          {"text": "🌱 Vegan", "value": "vegan"}
        ],
        "default": "all",
        "optional": false
      }
    ],
    "submit_label": "Save Alert",
    "notify_on_cancel": false
  }
}
